<?php
namespace Database\Seeders;
use App\Models\ElectronicService;use App\Models\PostCategory;use App\Models\User;use Illuminate\Database\Seeder;
class ElectronicServiceSeeder extends Seeder{public function run():void{$admin=User::first();$cat=PostCategory::where('slug','services-systems')->first();$items=['صدور پروانه کسب','تمدید پروانه کسب','انتقال پروانه','ثبت شکایت صنفی','پیگیری درخواست','ثبت‌نام دوره آموزشی','استعلام واحد صنفی','دریافت فرم‌های صنفی'];foreach($items as $i=>$title){ElectronicService::updateOrCreate(['slug'=>'service-'.($i+1)],['title'=>$title,'short_description'=>'خدمت الکترونیک '.$title.' ویژه فعالان صنفی گرگان.','body'=>'<p>شرح کامل خدمت، مدارک لازم، مراحل انجام و لینک ورود از طریق این صفحه در اختیار کاربران قرار می‌گیرد.</p>','icon'=>['📝','🔄','🔁','📨','🔎','🎓','✅','📄'][$i],'image'=>'assets/img/asnaf-gorgan-default.jpg','link'=>$i===3?route('complaints.create'):'#','link_type'=>$i===3?'internal':'external','target'=>$i===3?'_self':'_blank','category_id'=>$cat?->id,'status'=>'published','published_at'=>now()->subDays($i),'created_by'=>$admin?->id,'approved_by'=>$admin?->id,'sort_order'=>$i+1,'is_active'=>true]);}}}
